Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportAreaCidAreCidadeWC-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CIDNOM' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CidNom1.FromString(&GridStateDynamicFilter.Value) If not &CidNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cidade Nome", "Começa com") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cidade Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CidNom1) EndIf Case &DynamicFiltersSelector1 = !'UFENOM' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &UfeNom1.FromString(&GridStateDynamicFilter.Value) If not &UfeNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Estado Nome", "Começa com") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Estado Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&UfeNom1) EndIf Case &DynamicFiltersSelector1 = !'PAINOM' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &PaiNom1.FromString(&GridStateDynamicFilter.Value) If not &PaiNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "País Nome", "Começa com") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "País Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&PaiNom1) EndIf Case &DynamicFiltersSelector1 = !'CIDCOD' &CidCod1.FromString(&GridStateDynamicFilter.Value) If not &CidCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód. Cidade" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CidCod1 EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CIDNOM' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CidNom2.FromString(&GridStateDynamicFilter.Value) If not &CidNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cidade Nome", "Começa com") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cidade Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CidNom2) EndIf Case &DynamicFiltersSelector2 = !'UFENOM' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &UfeNom2.FromString(&GridStateDynamicFilter.Value) If not &UfeNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Estado Nome", "Começa com") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Estado Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&UfeNom2) EndIf Case &DynamicFiltersSelector2 = !'PAINOM' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &PaiNom2.FromString(&GridStateDynamicFilter.Value) If not &PaiNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "País Nome", "Começa com") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "País Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&PaiNom2) EndIf Case &DynamicFiltersSelector2 = !'CIDCOD' &CidCod2.FromString(&GridStateDynamicFilter.Value) If not &CidCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód. Cidade" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CidCod2 EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CIDNOM' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CidNom3.FromString(&GridStateDynamicFilter.Value) If not &CidNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cidade Nome", "Começa com") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cidade Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CidNom3) EndIf Case &DynamicFiltersSelector3 = !'UFENOM' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &UfeNom3.FromString(&GridStateDynamicFilter.Value) If not &UfeNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Estado Nome", "Começa com") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Estado Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&UfeNom3) EndIf Case &DynamicFiltersSelector3 = !'PAINOM' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &PaiNom3.FromString(&GridStateDynamicFilter.Value) If not &PaiNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "País Nome", "Começa com") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "País Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&PaiNom3) EndIf Case &DynamicFiltersSelector3 = !'CIDCOD' &CidCod3.FromString(&GridStateDynamicFilter.Value) If not &CidCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód. Cidade" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CidCod3 EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Cidade" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Nome" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "IBGE" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "UF" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Estado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "País" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "País Nome" &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "População" &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = "Ws"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod CidCod when &OrderedBy = 1 order EmpCod CidAreCod CidCod when &OrderedBy = 2 AND &OrderedDsc = False order (EmpCod) (CidAreCod) (CidCod) when &OrderedBy = 2 AND &OrderedDsc = True order EmpCod CidAreCod CidNom when &OrderedBy = 3 AND &OrderedDsc = False order (EmpCod) (CidAreCod) (CidNom) when &OrderedBy = 3 AND &OrderedDsc = True order EmpCod CidAreCod CidIBGE when &OrderedBy = 4 AND &OrderedDsc = False order (EmpCod) (CidAreCod) (CidIBGE) when &OrderedBy = 4 AND &OrderedDsc = True order EmpCod CidAreCod UfeCod when &OrderedBy = 5 AND &OrderedDsc = False order (EmpCod) (CidAreCod) (UfeCod) when &OrderedBy = 5 AND &OrderedDsc = True order EmpCod CidAreCod UfeNom when &OrderedBy = 6 AND &OrderedDsc = False order (EmpCod) (CidAreCod) (UfeNom) when &OrderedBy = 6 AND &OrderedDsc = True order EmpCod CidAreCod PaiCod when &OrderedBy = 7 AND &OrderedDsc = False order (EmpCod) (CidAreCod) (PaiCod) when &OrderedBy = 7 AND &OrderedDsc = True order EmpCod CidAreCod PaiNom when &OrderedBy = 8 AND &OrderedDsc = False order (EmpCod) (CidAreCod) (PaiNom) when &OrderedBy = 8 AND &OrderedDsc = True order EmpCod CidAreCod CidPop when &OrderedBy = 9 AND &OrderedDsc = False order (EmpCod) (CidAreCod) (CidPop) when &OrderedBy = 9 AND &OrderedDsc = True order EmpCod CidAreCod CidWs when &OrderedBy = 10 AND &OrderedDsc = False order (EmpCod) (CidAreCod) (CidWs) when &OrderedBy = 10 AND &OrderedDsc = True
Where EmpCod = &EmpCod and CidAreCod = &CidAreCod Where CidNom like &CidNom1 when &DynamicFiltersSelector1 = !'CIDNOM' AND &DynamicFiltersOperator1 = 0 AND (not &CidNom1.IsEmpty()) Where CidNom like '%' + &CidNom1 when &DynamicFiltersSelector1 = !'CIDNOM' AND &DynamicFiltersOperator1 = 1 AND (not &CidNom1.IsEmpty()) Where UfeNom like &UfeNom1 when &DynamicFiltersSelector1 = !'UFENOM' AND &DynamicFiltersOperator1 = 0 AND (not &UfeNom1.IsEmpty()) Where UfeNom like '%' + &UfeNom1 when &DynamicFiltersSelector1 = !'UFENOM' AND &DynamicFiltersOperator1 = 1 AND (not &UfeNom1.IsEmpty()) Where PaiNom like &PaiNom1 when &DynamicFiltersSelector1 = !'PAINOM' AND &DynamicFiltersOperator1 = 0 AND (not &PaiNom1.IsEmpty()) Where PaiNom like '%' + &PaiNom1 when &DynamicFiltersSelector1 = !'PAINOM' AND &DynamicFiltersOperator1 = 1 AND (not &PaiNom1.IsEmpty()) Where CidCod = &CidCod1 when &DynamicFiltersSelector1 = !'CIDCOD' AND (not &CidCod1.IsEmpty()) Where CidNom like &CidNom2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'CIDNOM' AND &DynamicFiltersOperator2 = 0 AND (not &CidNom2.IsEmpty()) Where CidNom like '%' + &CidNom2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'CIDNOM' AND &DynamicFiltersOperator2 = 1 AND (not &CidNom2.IsEmpty()) Where UfeNom like &UfeNom2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'UFENOM' AND &DynamicFiltersOperator2 = 0 AND (not &UfeNom2.IsEmpty()) Where UfeNom like '%' + &UfeNom2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'UFENOM' AND &DynamicFiltersOperator2 = 1 AND (not &UfeNom2.IsEmpty()) Where PaiNom like &PaiNom2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'PAINOM' AND &DynamicFiltersOperator2 = 0 AND (not &PaiNom2.IsEmpty()) Where PaiNom like '%' + &PaiNom2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'PAINOM' AND &DynamicFiltersOperator2 = 1 AND (not &PaiNom2.IsEmpty()) Where CidCod = &CidCod2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'CIDCOD' AND (not &CidCod2.IsEmpty()) Where CidNom like &CidNom3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'CIDNOM' AND &DynamicFiltersOperator3 = 0 AND (not &CidNom3.IsEmpty()) Where CidNom like '%' + &CidNom3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'CIDNOM' AND &DynamicFiltersOperator3 = 1 AND (not &CidNom3.IsEmpty()) Where UfeNom like &UfeNom3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'UFENOM' AND &DynamicFiltersOperator3 = 0 AND (not &UfeNom3.IsEmpty()) Where UfeNom like '%' + &UfeNom3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'UFENOM' AND &DynamicFiltersOperator3 = 1 AND (not &UfeNom3.IsEmpty()) Where PaiNom like &PaiNom3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'PAINOM' AND &DynamicFiltersOperator3 = 0 AND (not &PaiNom3.IsEmpty()) Where PaiNom like '%' + &PaiNom3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'PAINOM' AND &DynamicFiltersOperator3 = 1 AND (not &PaiNom3.IsEmpty()) Where CidCod = &CidCod3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'CIDCOD' AND (not &CidCod3.IsEmpty())
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = CidCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(CidNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Number = CidIBGE &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = WWP_Export_SecureText(UfeCod) &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = WWP_Export_SecureText(UfeNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Number = PaiCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = WWP_Export_SecureText(PaiNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Number = CidPop &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = CidWs.EnumerationDescription()
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"AreaCidAreCidadeWCGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"AreaCidAreCidadeWCGridState")) Else &GridState.FromXml(&Session.Get(!"AreaCidAreCidadeWCGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PARM_&EMPCOD" &EmpCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PARM_&CIDARECOD" &CidAreCod.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
